        }
    }

    foreach ($kvp in $targetCounts.GetEnumerator()) {
        [System.Collections.Generic.List[string]]$sources = [System.Collections.Generic.List[string]]$kvp.Value
        if ($sources.Count -gt 1) {
            $conflicts.Add([PSCustomObject]@{
