        New-Item -ItemType File -Path (Join-Path $script:testDir 'file_a.txt') | Out-Null

        [PSCustomObject[]]$plan = @(Get-RenamePreview -Path $script:testDir -Pattern 'file_a' -Replacement 'file_b')
