                NewName     = 'y.txt'
                FullOldPath = '/nonexistent/path/x.txt'
                FullNewPath = '/nonexistent/path/y.txt'
            }
        )

        { Invoke-FileRename -RenamePlan $badPlan } | Should -Throw
    }
}

